INSERT INTO KRBA_BRNO_TMP_S_I ( BAS_YYYY,VALT_TRN,VALT_BRNO,TONGJE_OPR_VALT_ID,SNO,DATA01,DATA02,DATA03,DATA04,DATA05,DATA06,DATA07,DATA08,DATA09,DATA10,DATA11,DATA12,DATA13,DATA14,DATA15,DATA16,DR_DT,DR_TIME,DR_OP_JKW_NO ) SELECT #{basYyyy} AS BAS_YYYY ,VALT_TRN AS VALT_TRN ,VALT_BRNO AS VALT_BRNO ,TONGJE_OPR_VALT_ID ,RN AS SNO ,VALT_BRNO AS DATA01 ,DPRT_NM AS DATA02 ,ORIG_CLNT_NAME AS DATA03 -- 고객명 ,ORIG_ENNM AS DATA04 -- 영문명 ,ORIG_CNO AS DATA05 -- 실명번호 ,CDD_FLFL_DATE AS DATA06 -- CDD 등록일자 ,CDD_RGSN_RESN_NAME AS DATA07 -- 등록 사유 ,TGT_CLNT_NAME AS DATA08 -- 대리인명 ,TGT_ENNM AS DATA09 -- 대리인 영문명 ,TGT_CNO AS DATA10 -- 대리인 실명번호 ,TGT_CDD_DATE AS DATA11 -- 대리인 CDD일자 ,RNMCNO AS DATA12 ,'' DATA13 ,'' DATA14 ,'' DATA15 ,'' DATA16 ,TO_CHAR(SYSDATE,'YYYYMMDD'),TO_CHAR(SYSDATE,'HH24MISS'),'BATCH' FROM ( SELECT TONGJE_OPR_VALT_ID ,TO_NUMBER(SUBSTR(#{basYymm},5,2)) AS VALT_TRN ,CDD_TAGT_ENTY_ID RNMCNO ,VALT_BRNO -- 부점코드 ,(SELECT DPRT_NM FROM NIC41B WHERE DPRT_CD = VALT_BRNO) DPRT_NM --부점명 ,ORIG_CLNT_NAME -- 고객명 ,ORIG_ENNM -- 영문명 ,ORIG_CNO -- 실명번호 ,CDD_FLFL_DATE AS CDD_FLFL_DATE -- CDD 등록일자 ,CDD_RGSN_RESN_NAME ,(CASE WHEN CDD_TAGT_SECT_CODE = '02' THEN TAGT_CLNT_NAME ELSE NULL END) TGT_CLNT_NAME -- 대리인명 ,(CASE WHEN CDD_TAGT_SECT_CODE = '02' THEN TAGT_ENNM ELSE NULL END) TGT_ENNM -- 대리인 영문명 ,(CASE WHEN CDD_TAGT_SECT_CODE = '02' THEN TGT_CNO ELSE NULL END) TGT_CNO -- 대리인 실명번호 ,(CASE WHEN CDD_TAGT_SECT_CODE = '02' THEN CDD_FLFL_DATE ELSE NULL END) TGT_CDD_DATE -- 대리인 CDD일자 ,RN FROM ( SELECT 'P040102' AS TONGJE_OPR_VALT_ID --P040102 개인 및 임의단체 CDD 실적 ,C.RGBR_CODE AS VALT_BRNO --등록지점 ,C.CDD_TAGT_ENTY_ID ,C.CDD_TAGT_SECT_CODE -- 01 본인 ,02 대리인 03 의뢰인 ,(CASE WHEN C.CDD_TAGT_SECT_CODE = '01' THEN '본인' WHEN C.CDD_TAGT_SECT_CODE = '02' THEN '대리인' ELSE '의뢰인' END) CDD_TAGT_SECT_NM ,C.CDD_CLNT_SECT_CODE -- 고객구분 1 개인 ,2 영리법인 ,3 비영리 법인 ,C.TAGT_CLNT_NAME --고객명 ,C.ORIG_CLNT_NAME -- 원천 고객명 ,C.CDD_ORIG_ENTY_ID -- 원천 고객번호 ,C.TAGT_ENNM --고객영문명 ,C.ORIG_ENNM --원천영문명 ,C.CDD_TAGT_CLNT_NO_CRYP TGT_CNO -- 대상 실명번호 ,C.CDD_ORIG_CLNT_NO_CRYP ORIG_CNO -- 원천 실명번호 ,C.CDD_FLFL_DATE -- CDD 등록일자 ,'' AS O_CDD_FLFL_DATE -- 원천 CDD 등록일자 ,C.CDD_RGSN_RESN_CODE -- CDD 등록코드 ,(CASE WHEN C.CDD_RGSN_RESN_CODE = '01' THEN '계좌개설' WHEN C.CDD_RGSN_RESN_CODE = '02' THEN '고객주요정보변경' WHEN C.CDD_RGSN_RESN_CODE = '03' THEN '약정및청약' WHEN C.CDD_RGSN_RESN_CODE = '04' THEN '계약기반거래' WHEN C.CDD_RGSN_RESN_CODE = '05' THEN '일회성금융거래(무통장송금)' WHEN C.CDD_RGSN_RESN_CODE = '06' THEN '퇴직연금' WHEN C.CDD_RGSN_RESN_CODE = '07' THEN '계약 및 Deal 신규' WHEN C.CDD_RGSN_RESN_CODE = '07' THEN '방카슈랑스' WHEN C.CDD_RGSN_RESN_CODE = '08' THEN '계약기반거래(외환)' WHEN C.CDD_RGSN_RESN_CODE = '08' THEN '재이행주기 정보갱신' WHEN C.CDD_RGSN_RESN_CODE = '09' THEN '대리인거래' WHEN C.CDD_RGSN_RESN_CODE = '10' THEN '직원알기수행(KYE)' WHEN C.CDD_RGSN_RESN_CODE = '94' THEN '상속업무(망자)' WHEN C.CDD_RGSN_RESN_CODE = '95' THEN '지속적고객확인' WHEN C.CDD_RGSN_RESN_CODE = '96' THEN '지속적고객확인(비대면)' WHEN C.CDD_RGSN_RESN_CODE = '97' THEN '지속적고객확인(온라인)' WHEN C.CDD_RGSN_RESN_CODE = '98' THEN '자금세탁우려' WHEN C.CDD_RGSN_RESN_CODE = '99' THEN '기타(직접입력)' ELSE C.CDD_RGSN_RESN_NAME END ) CDD_RGSN_RESN_NAME -- CDD 등록사유명 , ROW_NUMBER() OVER ( PARTITION BY C.RGBR_CODE ORDER BY DBMS_RANDOM.VALUE ) AS RN FROM SID.IDO_A_MAH_CDD_FLFL_DTLD C WHERE 1=1 AND C.CDD_CLNT_SECT_CODE = '1' --1:개인 2:영리법인 3:비영리법인 AND C.CDD_CMPL_YN = 'Y' --CDD완료여부 AND C.CDD_FLFL_DATE BETWEEN #{tgtTrnSdt} AND #{tgtTrnEdt}
UNION ALL
SELECT 'P040101' AS TONGJE_OPR_VALT_ID --P040101 법인고객 CDD 실적 ,C.RGBR_CODE AS VALT_BRNO --등록지점 ,C.CDD_TAGT_ENTY_ID ,C.CDD_TAGT_SECT_CODE -- 01 본인 ,02 대리인 03 의뢰인 ,(CASE WHEN C.CDD_TAGT_SECT_CODE = '01' THEN '본인' WHEN C.CDD_TAGT_SECT_CODE = '02' THEN '대리인' ELSE '의뢰인' END) CDD_TAGT_SECT_NM ,C.CDD_CLNT_SECT_CODE -- 고객구분 1 개인 ,2 영리법인 ,3 비영리 법인 ,C.TAGT_CLNT_NAME --고객명 ,C.ORIG_CLNT_NAME -- 원천 고객명 ,C.CDD_ORIG_ENTY_ID -- 원천 고객번호 ,C.TAGT_ENNM --고객영문명 ,C.ORIG_ENNM --원천영문명 ,C.CDD_TAGT_CLNT_NO_CRYP TGT_CNO -- 대상 실명번호 ,C.CDD_ORIG_CLNT_NO_CRYP ORIG_CNO -- 원천 실명번호 ,C.CDD_FLFL_DATE -- CDD 등록일자 ,'' AS O_CDD_FLFL_DATE -- 원천 CDD 등록일자 ,C.CDD_RGSN_RESN_CODE -- CDD 등록코드 ,(CASE WHEN C.CDD_RGSN_RESN_CODE = '01' THEN '계좌개설' WHEN C.CDD_RGSN_RESN_CODE = '02' THEN '고객주요정보변경' WHEN C.CDD_RGSN_RESN_CODE = '03' THEN '약정및청약' WHEN C.CDD_RGSN_RESN_CODE = '04' THEN '계약기반거래' WHEN C.CDD_RGSN_RESN_CODE = '05' THEN '일회성금융거래(무통장송금)' WHEN C.CDD_RGSN_RESN_CODE = '06' THEN '퇴직연금' WHEN C.CDD_RGSN_RESN_CODE = '07' THEN '계약 및 Deal 신규' WHEN C.CDD_RGSN_RESN_CODE = '07' THEN '방카슈랑스' WHEN C.CDD_RGSN_RESN_CODE = '08' THEN '계약기반거래(외환)' WHEN C.CDD_RGSN_RESN_CODE = '08' THEN '재이행주기 정보갱신' WHEN C.CDD_RGSN_RESN_CODE = '09' THEN '대리인거래' WHEN C.CDD_RGSN_RESN_CODE = '10' THEN '직원알기수행(KYE)' WHEN C.CDD_RGSN_RESN_CODE = '94' THEN '상속업무(망자)' WHEN C.CDD_RGSN_RESN_CODE = '95' THEN '지속적고객확인' WHEN C.CDD_RGSN_RESN_CODE = '96' THEN '지속적고객확인(비대면)' WHEN C.CDD_RGSN_RESN_CODE = '97' THEN '지속적고객확인(온라인)' WHEN C.CDD_RGSN_RESN_CODE = '98' THEN '자금세탁우려' WHEN C.CDD_RGSN_RESN_CODE = '99' THEN '기타(직접입력)' ELSE C.CDD_RGSN_RESN_NAME END ) CDD_RGSN_RESN_NAME -- CDD 등록사유명 , ROW_NUMBER() OVER ( PARTITION BY C.RGBR_CODE ORDER BY DBMS_RANDOM.VALUE ) AS RN FROM SID.IDO_A_MAH_CDD_FLFL_DTLD C WHERE 1=1 AND C.CDD_CLNT_SECT_CODE IN ( '2','3' ) --1:개인 2:영리법인 3:비영리법인 AND C.CDD_CMPL_YN = 'Y' --CDD완료여부 AND C.CDD_FLFL_DATE BETWEEN #{tgtTrnSdt} AND #{tgtTrnEdt}
UNION ALL
SELECT 'P040202' AS TONGJE_OPR_VALT_ID --P040202 개인 및 임의단체 EDD 실적 ,C.RGBR_CODE AS VALT_BRNO --등록지점 ,C.CDD_TAGT_ENTY_ID ,C.CDD_TAGT_SECT_CODE -- 01 본인 ,02 대리인 03 의뢰인 ,(CASE WHEN C.CDD_TAGT_SECT_CODE = '01' THEN '본인' WHEN C.CDD_TAGT_SECT_CODE = '02' THEN '대리인' ELSE '의뢰인' END) CDD_TAGT_SECT_NM ,C.CDD_CLNT_SECT_CODE -- 고객구분 1 개인 ,2 영리법인 ,3 비영리 법인 ,C.TAGT_CLNT_NAME --고객명 ,C.ORIG_CLNT_NAME -- 원천 고객명 ,C.CDD_ORIG_ENTY_ID -- 원천 고객번호 ,C.TAGT_ENNM --고객영문명 ,C.ORIG_ENNM --원천영문명 ,C.CDD_TAGT_CLNT_NO_CRYP TGT_CNO -- 대상 실명번호 ,C.CDD_ORIG_CLNT_NO_CRYP ORIG_CNO -- 원천 실명번호 ,C.CDD_FLFL_DATE -- CDD 등록일자 ,'' AS O_CDD_FLFL_DATE -- 원천 CDD 등록일자 ,C.CDD_RGSN_RESN_CODE -- CDD 등록코드 ,(CASE WHEN C.CDD_RGSN_RESN_CODE = '01' THEN '계좌개설' WHEN C.CDD_RGSN_RESN_CODE = '02' THEN '고객주요정보변경' WHEN C.CDD_RGSN_RESN_CODE = '03' THEN '약정및청약' WHEN C.CDD_RGSN_RESN_CODE = '04' THEN '계약기반거래' WHEN C.CDD_RGSN_RESN_CODE = '05' THEN '일회성금융거래(무통장송금)' WHEN C.CDD_RGSN_RESN_CODE = '06' THEN '퇴직연금' WHEN C.CDD_RGSN_RESN_CODE = '07' THEN '계약 및 Deal 신규' WHEN C.CDD_RGSN_RESN_CODE = '07' THEN '방카슈랑스' WHEN C.CDD_RGSN_RESN_CODE = '08' THEN '계약기반거래(외환)' WHEN C.CDD_RGSN_RESN_CODE = '08' THEN '재이행주기 정보갱신' WHEN C.CDD_RGSN_RESN_CODE = '09' THEN '대리인거래' WHEN C.CDD_RGSN_RESN_CODE = '10' THEN '직원알기수행(KYE)' WHEN C.CDD_RGSN_RESN_CODE = '94' THEN '상속업무(망자)' WHEN C.CDD_RGSN_RESN_CODE = '95' THEN '지속적고객확인' WHEN C.CDD_RGSN_RESN_CODE = '96' THEN '지속적고객확인(비대면)' WHEN C.CDD_RGSN_RESN_CODE = '97' THEN '지속적고객확인(온라인)' WHEN C.CDD_RGSN_RESN_CODE = '98' THEN '자금세탁우려' WHEN C.CDD_RGSN_RESN_CODE = '99' THEN '기타(직접입력)' ELSE C.CDD_RGSN_RESN_NAME END ) CDD_RGSN_RESN_NAME -- CDD 등록사유명 , ROW_NUMBER() OVER ( PARTITION BY C.RGBR_CODE ORDER BY DBMS_RANDOM.VALUE ) AS RN FROM SID.IDO_A_MAH_CDD_FLFL_DTLD C WHERE 1=1 AND C.CDD_CLNT_SECT_CODE = '1' --1:개인 2:영리법인 3:비영리법인 AND C.EDD_TAGT_YN = 'Y' --EDD대상여부 AND C.CDD_FLFL_DATE BETWEEN #{tgtTrnSdt} AND #{tgtTrnEdt}
UNION ALL
SELECT 'P040201' AS TONGJE_OPR_VALT_ID --P040201 법인고객 EDD 실적 ,C.RGBR_CODE AS VALT_BRNO --등록지점 ,C.CDD_TAGT_ENTY_ID ,C.CDD_TAGT_SECT_CODE -- 01 본인 ,02 대리인 03 의뢰인 ,(CASE WHEN C.CDD_TAGT_SECT_CODE = '01' THEN '본인' WHEN C.CDD_TAGT_SECT_CODE = '02' THEN '대리인' ELSE '의뢰인' END) CDD_TAGT_SECT_NM ,C.CDD_CLNT_SECT_CODE -- 고객구분 1 개인 ,2 영리법인 ,3 비영리 법인 ,C.TAGT_CLNT_NAME --고객명 ,C.ORIG_CLNT_NAME -- 원천 고객명 ,C.CDD_ORIG_ENTY_ID -- 원천 고객번호 ,C.TAGT_ENNM --고객영문명 ,C.ORIG_ENNM --원천영문명 ,C.CDD_TAGT_CLNT_NO_CRYP TGT_CNO -- 대상 실명번호 ,C.CDD_ORIG_CLNT_NO_CRYP ORIG_CNO -- 원천 실명번호 ,C.CDD_FLFL_DATE -- CDD 등록일자 ,'' AS O_CDD_FLFL_DATE -- 원천 CDD 등록일자 ,C.CDD_RGSN_RESN_CODE -- CDD 등록코드 ,(CASE WHEN C.CDD_RGSN_RESN_CODE = '01' THEN '계좌개설' WHEN C.CDD_RGSN_RESN_CODE = '02' THEN '고객주요정보변경' WHEN C.CDD_RGSN_RESN_CODE = '03' THEN '약정및청약' WHEN C.CDD_RGSN_RESN_CODE = '04' THEN '계약기반거래' WHEN C.CDD_RGSN_RESN_CODE = '05' THEN '일회성금융거래(무통장송금)' WHEN C.CDD_RGSN_RESN_CODE = '06' THEN '퇴직연금' WHEN C.CDD_RGSN_RESN_CODE = '07' THEN '계약 및 Deal 신규' WHEN C.CDD_RGSN_RESN_CODE = '07' THEN '방카슈랑스' WHEN C.CDD_RGSN_RESN_CODE = '08' THEN '계약기반거래(외환)' WHEN C.CDD_RGSN_RESN_CODE = '08' THEN '재이행주기 정보갱신' WHEN C.CDD_RGSN_RESN_CODE = '09' THEN '대리인거래' WHEN C.CDD_RGSN_RESN_CODE = '10' THEN '직원알기수행(KYE)' WHEN C.CDD_RGSN_RESN_CODE = '94' THEN '상속업무(망자)' WHEN C.CDD_RGSN_RESN_CODE = '95' THEN '지속적고객확인' WHEN C.CDD_RGSN_RESN_CODE = '96' THEN '지속적고객확인(비대면)' WHEN C.CDD_RGSN_RESN_CODE = '97' THEN '지속적고객확인(온라인)' WHEN C.CDD_RGSN_RESN_CODE = '98' THEN '자금세탁우려' WHEN C.CDD_RGSN_RESN_CODE = '99' THEN '기타(직접입력)' ELSE C.CDD_RGSN_RESN_NAME END ) CDD_RGSN_RESN_NAME -- CDD 등록사유명 , ROW_NUMBER() OVER ( PARTITION BY C.RGBR_CODE ORDER BY DBMS_RANDOM.VALUE ) AS RN FROM SID.IDO_A_MAH_CDD_FLFL_DTLD C WHERE 1=1 AND C.CDD_CLNT_SECT_CODE IN ( '2','3' ) --1:개인 2:영리법인 3:비영리법인 AND C.EDD_TAGT_YN = 'Y' --EDD대상여부 AND C.CDD_FLFL_DATE BETWEEN #{tgtTrnSdt} AND #{tgtTrnEdt}
UNION ALL
SELECT 'P040203' AS TONGJE_OPR_VALT_ID --P040203 비대면 CDD/EDD 실적 ,'20500' AS VALT_BRNO --등록지점 20500 자금세탁사기예방팀 고정 ,C.CDD_TAGT_ENTY_ID ,C.CDD_TAGT_SECT_CODE -- 01 본인 ,02 대리인 03 의뢰인 ,(CASE WHEN C.CDD_TAGT_SECT_CODE = '01' THEN '본인' WHEN C.CDD_TAGT_SECT_CODE = '02' THEN '대리인' ELSE '의뢰인' END) CDD_TAGT_SECT_NM ,C.CDD_CLNT_SECT_CODE -- 고객구분 1 개인 ,2 영리법인 ,3 비영리 법인 ,C.TAGT_CLNT_NAME --고객명 ,C.ORIG_CLNT_NAME -- 원천 고객명 ,C.CDD_ORIG_ENTY_ID -- 원천 고객번호 ,C.TAGT_ENNM --고객영문명 ,C.ORIG_ENNM --원천영문명 ,C.CDD_TAGT_CLNT_NO_CRYP TGT_CNO -- 대상 실명번호 ,C.CDD_ORIG_CLNT_NO_CRYP ORIG_CNO -- 원천 실명번호 ,C.CDD_FLFL_DATE -- CDD 등록일자 ,'' AS O_CDD_FLFL_DATE -- 원천 CDD 등록일자 ,C.CDD_RGSN_RESN_CODE -- CDD 등록코드 ,(CASE WHEN C.CDD_RGSN_RESN_CODE = '01' THEN '계좌개설' WHEN C.CDD_RGSN_RESN_CODE = '02' THEN '고객주요정보변경' WHEN C.CDD_RGSN_RESN_CODE = '03' THEN '약정및청약' WHEN C.CDD_RGSN_RESN_CODE = '04' THEN '계약기반거래' WHEN C.CDD_RGSN_RESN_CODE = '05' THEN '일회성금융거래(무통장송금)' WHEN C.CDD_RGSN_RESN_CODE = '06' THEN '퇴직연금' WHEN C.CDD_RGSN_RESN_CODE = '07' THEN '계약 및 Deal 신규' WHEN C.CDD_RGSN_RESN_CODE = '07' THEN '방카슈랑스' WHEN C.CDD_RGSN_RESN_CODE = '08' THEN '계약기반거래(외환)' WHEN C.CDD_RGSN_RESN_CODE = '08' THEN '재이행주기 정보갱신' WHEN C.CDD_RGSN_RESN_CODE = '09' THEN '대리인거래' WHEN C.CDD_RGSN_RESN_CODE = '10' THEN '직원알기수행(KYE)' WHEN C.CDD_RGSN_RESN_CODE = '94' THEN '상속업무(망자)' WHEN C.CDD_RGSN_RESN_CODE = '95' THEN '지속적고객확인' WHEN C.CDD_RGSN_RESN_CODE = '96' THEN '지속적고객확인(비대면)' WHEN C.CDD_RGSN_RESN_CODE = '97' THEN '지속적고객확인(온라인)' WHEN C.CDD_RGSN_RESN_CODE = '98' THEN '자금세탁우려' WHEN C.CDD_RGSN_RESN_CODE = '99' THEN '기타(직접입력)' ELSE C.CDD_RGSN_RESN_NAME END ) CDD_RGSN_RESN_NAME -- CDD 등록사유명 , ROW_NUMBER() OVER ( PARTITION BY C.RGBR_CODE ORDER BY DBMS_RANDOM.VALUE ) AS RN FROM SID.IDO_A_MAH_CDD_FLFL_DTLD C WHERE 1=1 AND ( C.PRCE_CHNL_SECT_CODE like 'G%' or C.PRCE_CHNL_SECT_CODE like 'H%' or C.PRCE_CHNL_SECT_CODE like 'I%') AND ( C.CDD_CMPL_YN = 'Y' OR C.EDD_TAGT_YN = 'Y' ) --CDD완료여부, EDD대상여부 AND C.CDD_FLFL_DATE BETWEEN #{tgtTrnSdt} AND #{tgtTrnEdt}
UNION ALL
