) M ,( SELECT RPT_GJDT ,JIPYO_ID ,JIPYO_V ,ROUND((JIPYO_V / UNIT_CTNT) * 100,2) TONGJE_VALD_PNT ,UNIT_CTNT FROM ( SELECT M.RPT_GJDT ,M.JIPYO_ID ,UNIT_CTNT ,NVL(JIPYO_V,0) JIPYO_V FROM ( SELECT RPT_GJDT ,JIPYO_ID ,UNIT_CTNT FROM RBA200TB WHERE RPT_GJDT = (SELECT MAX(RPT_GJDT) RPT_GJDT FROM RBA010TB WHERE BT_BAS_DT IS NOT NULL AND RPT_YN = '1') AND JIPYO_ID ='O1.07.0' ) M ,( SELECT RPT_GJDT ,COUNT(*) AS JIPYO_V FROM RBA110TB WHERE 1=1 AND RPT_GJDT = (SELECT MAX(RPT_GJDT) RPT_GJDT FROM RBA010TB WHERE BT_BAS_DT IS NOT NULL AND RPT_YN = '1') AND HM_CD = '02O1070101' AND HM_DATA_S = 1 GROUP BY RPT_GJDT ) A WHERE 1=1 AND M.RPT_GJDT = A.RPT_GJDT(+) ) M ) A WHERE 1=1 AND M.JIPYO = A.JIPYO_ID UNION ALL SELECT BAS_YYMM ,TONGJE_FLD_C ,TONGJE_LGDV_C ,TONGJE_MDDV_C ,TONGJE_SMDV_C ,VALT_BRNO ,JIPYO_OFFR_C ,VALD_VALT_METH_C ,JIPYO_V ,(CASE WHEN VALT_METH_C = 1 THEN TONGJE_VALD_PNT ELSE NULL END ) TONGJE_VALD_PNT ,RT_PNT ,(CASE WHEN VALT_METH_C = 1 THEN ROUND((TONGJE_VALD_PNT*RT_PNT)/100,2) ELSE NULL END) TONGJE_VALT_PNT FROM (
) M ,( SELECT RPT_GJDT ,JIPYO_ID ,JIPYO_V ,ROUND((JIPYO_V / UNIT_CTNT) * 100,2) TONGJE_VALD_PNT ,UNIT_CTNT FROM ( SELECT M.RPT_GJDT ,M.JIPYO_ID ,UNIT_CTNT ,NVL(JIPYO_V,0) JIPYO_V FROM ( SELECT RPT_GJDT ,JIPYO_ID ,UNIT_CTNT FROM RBA200TB WHERE RPT_GJDT = (SELECT MAX(RPT_GJDT) RPT_GJDT FROM RBA010TB WHERE BT_BAS_DT IS NOT NULL AND RPT_YN = '1') AND JIPYO_ID ='O1.03.0' ) M ,( SELECT NVL(SUM(COUNT(GJDT)), '0') AS JIPYO_V FROM RBA110TB WHERE 1=1 AND RPT_GJDT = (SELECT MAX(RPT_GJDT) RPT_GJDT FROM RBA010TB WHERE BT_BAS_DT IS NOT NULL AND RPT_YN = '1') AND HM_CD = '02O1030101' AND HM_DATA_S = 1 GROUP BY GJDT ) A WHERE 1=1
) M ) A WHERE 1=1 AND M.JIPYO = A.JIPYO_ID
